import { useState, useEffect } from 'react';
import { apiFetch } from '../data/db';

export default function Contact() {
  const [form, setForm] = useState({ name: '', email: '', phone: '', subject: '', message: '' });
  const [msg, setMsg] = useState('');
  const [msgType, setMsgType] = useState('');
  const [submitting, setSubmitting] = useState(false);
  const [submittedCount, setSubmittedCount] = useState(0);

  useEffect(() => {
    document.title = 'Contact - Gursons India';
    window.scrollTo(0, 0);
  }, []);

  async function handleSubmit(e) {
    e.preventDefault();
    if (!form.name || !form.email || !form.message) {
      setMsg('Please fill in all required fields.'); setMsgType('error'); return;
    }
    setSubmitting(true);
    const res = await apiFetch('/contact', { method: 'POST', body: JSON.stringify(form) });
    setSubmitting(false);
    if (res?.success) {
      setMsg(res.message); setMsgType('success');
    } else {
      setMsg('Message sent! We will contact you shortly.'); setMsgType('success');
    }
    setSubmittedCount(c => c + 1);
    setForm({ name: '', email: '', phone: '', subject: '', message: '' });
    setTimeout(() => setMsg(''), 5000);
  }

  const inputSt = {
    width: '100%', background: 'rgba(255,255,255,0.06)',
    border: '1px solid rgba(255,255,255,0.15)', color: '#fff',
    padding: '13px 16px', fontSize: 15, fontFamily: 'var(--font-body)',
    outline: 'none', borderRadius: 8, transition: 'all 0.2s',
  };

  const CONTACT_INFO = [
    { icon: '📍', label: 'Address', value: '2920, New Sunny Enclave, Sec-123, S.A.S. Nagar\nMohali, Punjab-140301, India' },
    { icon: '📞', label: 'Phone', value: '+91-9811034938\n+91-9872727725' },
    { icon: '✉️', label: 'Email', value: 'gursonsindia@gmail.com' },
    { icon: '🕐', label: 'Hours', value: 'Mon–Sat: 9:00 AM – 6:00 PM\nSunday: Closed' },
  ];

  return (
    <div className="page-enter" style={{ paddingTop: 70 }}>

      {/* HERO */}
      <section style={{
        padding: '100px 0 60px',
        background: 'linear-gradient(135deg, var(--navy) 0%, var(--navy-mid) 100%)',
        position: 'relative', overflow: 'hidden',
      }}>
        <div style={{
          position: 'absolute', inset: 0,
          backgroundImage: 'linear-gradient(rgba(255,255,255,0.025) 1px, transparent 1px), linear-gradient(90deg, rgba(255,255,255,0.025) 1px, transparent 1px)',
          backgroundSize: '60px 60px', pointerEvents: 'none',
        }} />
        <div className="container" style={{ position: 'relative', zIndex: 1 }}>
          <div className="eyebrow animate-fadeUp delay-1">Get In Touch</div>
          <h1 className="animate-fadeUp delay-2" style={{ fontFamily: 'var(--font-head)', fontSize: 'clamp(3rem, 7vw, 6rem)', fontWeight: 800, lineHeight: 1, letterSpacing: -2 }}>
            CONTACT<br /><span style={{ color: 'var(--gold)' }}>US</span>
          </h1>
          <p className="animate-fadeUp delay-3" style={{ color: 'var(--white-70)', fontSize: 16, marginTop: '1rem', maxWidth: 420 }}>
            Have a query about our products or need a quote?
            We'd love to hear from you.
          </p>
        </div>
      </section>

      {/* CONTACT LAYOUT */}
      <section className="section">
        <div className="container">
          <div style={{ display: 'grid', gridTemplateColumns: '1fr 1.5fr', gap: '4rem', alignItems: 'start' }}>

            {/* LEFT: Info */}
            <div>
              <div className="eyebrow">Reach Us</div>
              <h2 style={{ fontFamily: 'var(--font-head)', fontSize: 'clamp(1.8rem, 3vw, 2.5rem)', fontWeight: 800, marginBottom: '2rem' }}>
                Always Here<br /><span style={{ color: 'var(--gold)' }}>For You</span>
              </h2>

              <div style={{ display: 'flex', flexDirection: 'column', gap: '1.5rem' }}>
                {CONTACT_INFO.map(info => (
                  <div key={info.label} style={{
                    display: 'flex', gap: '1rem', alignItems: 'flex-start',
                    padding: '1.25rem', background: 'rgba(255,255,255,0.05)',
                    border: '1px solid rgba(255,255,255,0.1)', borderRadius: 10,
                    transition: 'all 0.3s',
                  }}
                    onMouseEnter={e => { e.currentTarget.style.borderColor = 'rgba(201,168,76,0.3)'; e.currentTarget.style.background = 'rgba(201,168,76,0.05)'; }}
                    onMouseLeave={e => { e.currentTarget.style.borderColor = 'rgba(255,255,255,0.1)'; e.currentTarget.style.background = 'rgba(255,255,255,0.05)'; }}
                  >
                    <div style={{ fontSize: 22, flexShrink: 0 }}>{info.icon}</div>
                    <div>
                      <div style={{ fontSize: 11, fontWeight: 700, letterSpacing: 2, textTransform: 'uppercase', color: 'var(--gold)', marginBottom: 4 }}>{info.label}</div>
                      <div style={{ fontSize: 14, color: 'var(--white-70)', lineHeight: 1.8, whiteSpace: 'pre-line' }}>{info.value}</div>
                    </div>
                  </div>
                ))}
              </div>

              {/* Message counter */}
              {submittedCount > 0 && (
                <div style={{
                  marginTop: '1.5rem', padding: '1rem 1.25rem',
                  background: 'rgba(34,197,94,0.1)', border: '1px solid rgba(34,197,94,0.2)',
                  borderRadius: 8, fontSize: 13, color: '#22C55E',
                }}>
                  ✓ {submittedCount} message{submittedCount > 1 ? 's' : ''} submitted this session
                </div>
              )}
            </div>

            {/* RIGHT: Form */}
            <div style={{
              background: 'rgba(255,255,255,0.04)', border: '1px solid rgba(255,255,255,0.1)',
              borderRadius: 16, padding: '2.5rem',
            }}>
              <h3 style={{ fontFamily: 'var(--font-head)', fontSize: 24, fontWeight: 700, marginBottom: '1.5rem' }}>
                Send a Message
              </h3>

              <form onSubmit={handleSubmit} style={{ display: 'flex', flexDirection: 'column', gap: '1rem' }}>
                <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '1rem' }}>
                  {[
                    { id: 'name', label: 'Full Name *', ph: 'Your name', type: 'text' },
                    { id: 'email', label: 'Email Address *', ph: 'your@email.com', type: 'email' },
                  ].map(f => (
                    <div key={f.id}>
                      <label style={{ display: 'block', fontSize: 11, fontWeight: 700, letterSpacing: 2, textTransform: 'uppercase', color: 'rgba(255,255,255,0.6)', marginBottom: 6 }}>{f.label}</label>
                      <input type={f.type} style={inputSt} placeholder={f.ph} value={form[f.id]}
                        onChange={e => setForm(fm => ({ ...fm, [f.id]: e.target.value }))}
                        onFocus={e => { e.target.style.borderColor = 'var(--gold)'; e.target.style.boxShadow = '0 0 0 3px rgba(201,168,76,0.1)'; }}
                        onBlur={e => { e.target.style.borderColor = 'rgba(255,255,255,0.15)'; e.target.style.boxShadow = 'none'; }}
                      />
                    </div>
                  ))}
                </div>

                <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '1rem' }}>
                  {[
                    { id: 'phone', label: 'Phone Number', ph: '+91 XXXXX XXXXX', type: 'tel' },
                    { id: 'subject', label: 'Subject', ph: 'Product inquiry', type: 'text' },
                  ].map(f => (
                    <div key={f.id}>
                      <label style={{ display: 'block', fontSize: 11, fontWeight: 700, letterSpacing: 2, textTransform: 'uppercase', color: 'rgba(255,255,255,0.6)', marginBottom: 6 }}>{f.label}</label>
                      <input type={f.type} style={inputSt} placeholder={f.ph} value={form[f.id]}
                        onChange={e => setForm(fm => ({ ...fm, [f.id]: e.target.value }))}
                        onFocus={e => { e.target.style.borderColor = 'var(--gold)'; e.target.style.boxShadow = '0 0 0 3px rgba(201,168,76,0.1)'; }}
                        onBlur={e => { e.target.style.borderColor = 'rgba(255,255,255,0.15)'; e.target.style.boxShadow = 'none'; }}
                      />
                    </div>
                  ))}
                </div>

                <div>
                  <label style={{ display: 'block', fontSize: 11, fontWeight: 700, letterSpacing: 2, textTransform: 'uppercase', color: 'rgba(255,255,255,0.6)', marginBottom: 6 }}>Your Message *</label>
                  <textarea style={{ ...inputSt, resize: 'vertical', minHeight: 130 }} placeholder="Tell us what you need..."
                    value={form.message}
                    onChange={e => setForm(fm => ({ ...fm, message: e.target.value }))}
                    onFocus={e => { e.target.style.borderColor = 'var(--gold)'; e.target.style.boxShadow = '0 0 0 3px rgba(201,168,76,0.1)'; }}
                    onBlur={e => { e.target.style.borderColor = 'rgba(255,255,255,0.15)'; e.target.style.boxShadow = 'none'; }}
                  />
                </div>

                <button type="submit" disabled={submitting}
                  style={{
                    background: submitting ? 'rgba(201,168,76,0.5)' : 'var(--gold)',
                    color: 'var(--navy)', border: 'none',
                    padding: '15px', borderRadius: 8, fontSize: 15, fontWeight: 700,
                    cursor: submitting ? 'not-allowed' : 'pointer',
                    fontFamily: 'var(--font-body)', letterSpacing: 0.5,
                    transition: 'all 0.2s',
                  }}
                  onMouseEnter={e => { if (!submitting) { e.target.style.background = 'var(--gold-light)'; e.target.style.transform = 'translateY(-2px)'; }}}
                  onMouseLeave={e => { e.target.style.background = submitting ? 'rgba(201,168,76,0.5)' : 'var(--gold)'; e.target.style.transform = 'none'; }}
                >
                  {submitting ? 'Sending...' : 'Send Message →'}
                </button>

                {msg && (
                  <div style={{
                    padding: '12px 16px', borderRadius: 8, fontSize: 14,
                    background: msgType === 'success' ? 'rgba(34,197,94,0.1)' : 'rgba(239,68,68,0.1)',
                    color: msgType === 'success' ? '#22C55E' : '#EF4444',
                    border: `1px solid ${msgType === 'success' ? 'rgba(34,197,94,0.3)' : 'rgba(239,68,68,0.3)'}`,
                  }}>
                    {msgType === 'success' ? '✓ ' : '✗ '}{msg}
                  </div>
                )}
              </form>
            </div>
          </div>
        </div>
      </section>
    </div>
  );
}
